SELECT i.model_name, i.manufacturer 
FROM ic_models i
WHERE i.last_updated_by NOT IN (SELECT user_id FROM users);

SELECT MIN(operating_temperature_range) AS min_operating_temperature,
       MAX(operating_temperature_range) AS max_operating_temperature
FROM ic_models;

SELECT model_name
FROM ic_models
WHERE operating_temperature_range = (
  SELECT MAX(operating_temperature_range)
  FROM ic_models
);

SELECT model_name, last_updated_date 
FROM ic_models 
WHERE model_id = (SELECT model_id FROM ic_models WHERE model_name = 'IC1000');
